          {/* ── Formasi default ── */}
          <div className="px-4 py-3 space-y-2">
            <div className="flex items-center gap-1.5 mb-1">
              <span className="text-xs font-bold uppercase tracking-[0.14em] text-muted-foreground">Formasi Default Operator</span>
