                    const assignments = assignmentsByPOS.get(proc.id) ?? [];
                    return (
                      <div key={proc.id} className="grid grid-cols-[4.5rem_1fr_1fr_2.5rem] gap-2 items-center px-3 py-2.5 hover:bg-slate-50/60 transition-colors">
