                        <span className="text-xs font-medium text-foreground">{proc.name}</span>
                        <div className="flex flex-wrap gap-1.5">
                          {assignments.length === 0 ? (
                            <span className="text-[11px] text-muted-foreground/50 italic">Kosong</span>
