// ─── Main Tab ─────────────────────────────────────────────────────────────────

const emptyGroupForm = (): { id?: string; code: string; sort_order: number; active: boolean } => ({
  code: "", sort_order: 0, active: true,
});


const GROUP_SORT: SortOption<Group>[] = [
  { label: "Urutan ↑",  fn: (a, b) => a.sort_order - b.sort_order },
  { label: "Kode A→Z",  fn: (a, b) => a.code.localeCompare(b.code) },
];

export function GroupsTab() {
  const qc = useQueryClient();
  const [selectedLineId, setSelectedLineId] = useState<string | null>(null);
  const [groupModal, setGroupModal] = useState(false);
  const [groupForm, setGroupForm]   = useState(emptyGroupForm());
  const [groupErrors, setGroupErrors] = useState<Record<string, string>>({});
  const clearGroupErr = (f: string) => setGroupErrors(e => { const n = { ...e }; delete n[f]; return n; });
  const groupErrCls   = (f: string) => groupErrors[f] ? "border-destructive focus-visible:ring-destructive" : "";

  const { data: lines       = [] } = useTable<Line>("lines",  { orderBy: "code", ascending: true });
  const { data: operators   = [] } = useTable<Operator>("operators", { orderBy: "full_name", ascending: true });
  const { data: leaderUsers = [] } = useLeaderUsers();
  const { data: groups      = [], refetch: refetchGroups } = useGroups(selectedLineId);
  const tc = useTableControls(groups, ["code"] as (keyof Group)[], GROUP_SORT);
  const { data: lineProcesses = [] } = useLineProcesses(selectedLineId);

  const effectiveLineId = selectedLineId ?? (lines[0]?.id ?? null);
  const selectedLine    = lines.find(l => l.id === effectiveLineId);

  // ── Group upsert ──
  const upsertGroup = useMutation({
    mutationFn: async (form: typeof groupForm & { line_id: string }) => {
      const { id, ...rest } = form;
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      const fn = id
        ? (supabase.from("groups") as any).update(rest).eq("id", id).select().single()
        : (supabase.from("groups") as any).insert(rest).select().single();
      const { data, error } = await fn;
      if (error) throw error;
      return data;
    },
    onSuccess: () => {
      toast.success("Tersimpan");
      qc.invalidateQueries({ queryKey: ["groups"] });
      setGroupModal(false);
    },
    onError: (e: Error) => toast.error(e.message),
  });

  // ── Group delete ──
  const deleteGroup = useMutation({
    mutationFn: async (id: string) => {
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      const { error } = await (supabase.from("groups") as any).delete().eq("id", id);
      if (error) throw error;
    },
    onSuccess: () => { toast.success("Group dihapus"); qc.invalidateQueries({ queryKey: ["groups"] }); },
    onError: (e: Error) => toast.error(e.message),
  });

  const openAdd  = () => {
    const maxSort = groups.length ? Math.max(...groups.map(g => g.sort_order)) : 0;
    setGroupForm({ ...emptyGroupForm(), sort_order: maxSort + 10 });
    setGroupErrors({});
    setGroupModal(true);
  };
  const openEdit = (g: Group) => {
    setGroupForm({ id: g.id, code: g.code, sort_order: g.sort_order, active: g.active });
    setGroupErrors({});
    setGroupModal(true);
  };

  const handleSubmit = () => {
    const newErr: Record<string, string> = {};
    if (!groupForm.code.trim()) newErr.code = "Kode group wajib diisi";
    if (!effectiveLineId)       newErr.line_id = "Pilih lini terlebih dahulu";
    if (Object.keys(newErr).length > 0) { setGroupErrors(newErr); return; }
    upsertGroup.mutate({ ...groupForm, line_id: effectiveLineId! });
  };

  // ── CSV Import ─────────────────────────────────────────────────────────
  const importGroups = async (rows: Record<string, string>[]) => {
    const lineMap = new Map(lines.map(l => [l.code.toUpperCase(), l.id]));
    const errors: string[] = [];
    const toInsert = rows
      .filter(r => r.line_code?.trim() && r.code?.trim())
      .map((r, i) => {
        const lid = lineMap.get(r.line_code.trim().toUpperCase());
        if (!lid) { errors.push(`${r.code}: line_code "${r.line_code}" tidak ditemukan`); return null; }
        return { line_id: lid, code: r.code.trim().toUpperCase(), sort_order: toInt(r.sort_order) ?? (i + 1) * 10, active: toBool(r.active) };
      })
      .filter(Boolean) as Record<string, unknown>[];
    if (!toInsert.length) return { imported: 0, errors: errors.length ? errors : ["Tidak ada baris valid"] };
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const { data, error } = await (supabase.from("groups") as any)
      .upsert(toInsert, { onConflict: "line_id,code" }).select();
    if (error) throw new Error(error.message);
    qc.invalidateQueries({ queryKey: ["groups"] });
    return { imported: (data ?? []).length, errors };
  };

  return (
    <div className="space-y-6">
      <div>
        <h2 className="text-base font-semibold">Group / Regu Shift</h2>
        <p className="text-xs text-muted-foreground mt-0.5">
          Setiap Line memiliki 1–N Group yang masing-masing bisa bertugas di Shift mana pun.
          Atur Leader (akun login) dan formasi default operator per Workstation di sini.
        </p>
      </div>

      {/* ── Line selector ── */}
      <div className="flex flex-wrap gap-2">
        {lines.map(line => (
          <button
            key={line.id}
            type="button"
            onClick={() => setSelectedLineId(line.id)}
            className={`inline-flex items-center gap-2 rounded-xl border px-4 py-2 text-sm font-semibold transition-colors ${
              (effectiveLineId === line.id)
                ? "border-primary bg-blue-50 text-primary shadow-sm"
                : "border-border text-muted-foreground hover:bg-muted"
            }`}
          >
            <span className={`h-2 w-2 rounded-full ${line.active ? "bg-emerald-500" : "bg-muted-foreground/40"}`} />
            {line.code}
          </button>
        ))}
        {lines.length === 0 && <p className="text-sm text-muted-foreground">Belum ada lini. Tambahkan di tab Lini Produksi.</p>}
      </div>

      {/* ── Group list ── */}
      {effectiveLineId && (
        <AdminSection
          title={`Group — ${selectedLine?.name ?? selectedLine?.code ?? ""}`}
          description="Kelola regu shift untuk lini ini. Setiap regu bisa punya Leader dan formasi operator berbeda."
          onAdd={openAdd}
          rightSlot={
            <CsvButtons
              templateFilename="template-groups.csv"
              templateHeaders={["line_code","code","sort_order","active"]}
              templateSample={["LINE-A","GRP-A",10,"true"]}
              onImport={importGroups}
            />
          }
        >
          <TableToolbar
            search={tc.search} onSearch={tc.setSearch}
            total={tc.total} filteredCount={tc.filteredCount}
            activeFilterCount={tc.activeFilterCount} onClearColFilters={tc.clearColFilters}
          />
          <div className="space-y-3">
            {tc.paged.length === 0 ? (
              <div className="py-8 text-center text-sm text-muted-foreground">
                Belum ada group untuk lini ini. Klik "+ Tambah"
              </div>
            ) : (
              tc.paged.map(group => (
                <GroupCard
                  key={group.id}
                  group={group}
                  lineProcesses={lineProcesses}
                  allOperators={operators}
                  leaderUsers={leaderUsers}
                  onEdit={openEdit}
                  onDelete={g => confirm(`Hapus group "${g.code}"?`) && deleteGroup.mutate(g.id)}
                  onRefresh={refetchGroups}
                />
              ))
            )}
          </div>
          <Pager page={tc.page} totalPages={tc.totalPages} onChange={tc.setPage}
            filteredCount={tc.filteredCount} total={tc.total} pageSize={tc.pageSize} onPageSizeChange={tc.setPageSize} />
        </AdminSection>
      )}

      {/* ── Modal: form group ── */}
      <FormModal
        open={groupModal}
        onOpenChange={setGroupModal}
        title={groupForm.id ? "Edit Group" : "Tambah Group"}
        onSubmit={handleSubmit}
        busy={upsertGroup.isPending}
      >
        <div className="space-y-1.5">
          <Label>Kode Group <span className="text-destructive">*</span></Label>
          <Input
            value={groupForm.code}
            placeholder="GRP-A"
            className={groupErrCls("code")}
            onChange={e => { clearGroupErr("code"); setGroupForm(f => ({ ...f, code: e.target.value.toUpperCase() })); }}
          />
          {groupErrors.code && <p className="text-[11px] text-destructive">{groupErrors.code}</p>}
        </div>
        <div className="grid grid-cols-2 gap-3">
          <div className="space-y-1.5">
            <Label>Urutan Tampil</Label>
            <Input
              type="number" min={0}
              value={groupForm.sort_order}
              onChange={e => setGroupForm(f => ({ ...f, sort_order: parseInt(e.target.value) || 0 }))}
            />
          </div>
          <div className="flex items-end justify-between pb-0.5">
            <Label>Aktif</Label>
            <Switch
              checked={groupForm.active}
              onCheckedChange={v => setGroupForm(f => ({ ...f, active: v }))}
            />
          </div>
        </div>
      </FormModal>
    </div>
  );
}

import { useState, useMemo } from "react";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { AdminSection, SortableDataTable, ColDef, RowActions, TableToolbar, Pager } from "@/components/admin/AdminSection";
import { FormModal } from "@/components/ui/form-modal";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Switch } from "@/components/ui/switch";
import { Button } from "@/components/ui/button";
import { Pencil, Trash2 } from "lucide-react";
import { useTable, useUpsert, useDeleteRow } from "@/hooks/useCrud";
import { CsvButtons } from "@/components/admin/CsvButtons";
import { toBool } from "@/lib/csv-utils";
import { useTableControls, SortOption } from "@/hooks/useTableControls";
import { toast } from "sonner";

// ─── Types ────────────────────────────────────────────────────────────────────

interface Product {
  id: string; code: string; name: string; model: string | null;
  category: string | null; description: string | null; active: boolean;
}

interface Line { id: string; code: string; name: string; }
interface RefItem { id: string; name: string; sort_order: number; active: boolean; }

// ─── Helpers ──────────────────────────────────────────────────────────────────

function categoryChip(cat: string | null): string {
  if (!cat) return "chip";
  const map: Record<string, string> = {
    "CCU":                    "chip chip-info",
    "Fuel Sender":            "chip chip-success",
    "Speedometer Digital":    "bg-violet-100 text-violet-700 chip",
    "Speedometer Mechanical": "bg-purple-100 text-purple-700 chip",
    "Winker Lamp":            "chip chip-warning",
    "ECU":                    "bg-cyan-100 text-cyan-700 chip",
    "CDI":                    "bg-teal-100 text-teal-700 chip",
  };
  return map[cat] ?? "chip";
}

// ─── Sort + ColDef ────────────────────────────────────────────────────────────

const PROD_SORT: SortOption<Product>[] = [
  { label: "Kode A→Z",     fn: (a, b) => a.code.localeCompare(b.code) },        // 0
  { label: "Kode Z→A",     fn: (a, b) => b.code.localeCompare(a.code) },        // 1
  { label: "Nama A→Z",     fn: (a, b) => a.name.localeCompare(b.name) },        // 2
  { label: "Kategori A→Z", fn: (a, b) => (a.category ?? "").localeCompare(b.category ?? "") }, // 3
];
const PROD_SEARCH: (keyof Product)[] = ["code", "name", "model", "category"];

const PROD_COLS: ColDef[] = [
  { label: "Kode",          sortAsc: 0, sortDesc: 1, filterKey: "code",     className: "w-28" },
  { label: "Kategori",      sortAsc: 3,               filterKey: "category", className: "w-32" },
  { label: "Nama",          sortAsc: 2,               filterKey: "name" },
  { label: "Model",                                   filterKey: "model",    className: "w-24" },
  { label: "Lini Produksi",                                                  className: "w-52" },
  { label: "Status",                                                         className: "w-20" },
  { label: "",                                                               className: "w-[80px]" },
];

const empty: Partial<Product> = { code:"", name:"", model:"", category:"", description:"", active:true };

// ─── Component ────────────────────────────────────────────────────────────────

export function ProductsTab() {
  const qc = useQueryClient();

  // Master data
  const { data = [], isLoading } = useTable<Product>("products", { orderBy:"code", ascending:true });
  const { data: refCats = [] }   = useTable<RefItem>("ref_product_categories", { orderBy:"sort_order", ascending:true });
  const { data: lines = [] }     = useTable<Line>("lines", { orderBy:"code", ascending:true });

  // product_lines junction table
  const { data: productLines = [] } = useQuery({
    queryKey: ["product-lines"],
    queryFn: async () => {
      const { data, error } = await (supabase.from("product_lines") as any)
        .select("product_id, line_id");
      if (error) throw error;
      return (data ?? []) as { product_id: string; line_id: string }[];
    },
  });

  // product_id → line_id[]
  const productLineMap = useMemo(() => {
    const m = new Map<string, string[]>();
    for (const row of productLines) {
      if (!m.has(row.product_id)) m.set(row.product_id, []);
      m.get(row.product_id)!.push(row.line_id);
    }
    return m;
  }, [productLines]);

  // line_id → Line (for display)
  const lineById = useMemo(() => new Map(lines.map(l => [l.id, l])), [lines]);

  const upsert = useUpsert("products");
  const del    = useDeleteRow("products");

  // Form state
  const [open, setOpen]               = useState(false);
  const [form, setForm]               = useState<Partial<Product>>(empty);
  const [formLineIds, setFormLineIds] = useState<string[]>([]);
  const [errors, setErrors]           = useState<Record<string, string>>({});
  const [saveBusy, setSaveBusy]       = useState(false);

  const clearErr = (f: string) => setErrors(e => { const n = { ...e }; delete n[f]; return n; });
  const errCls   = (f: string) => errors[f] ? "border-destructive focus-visible:ring-destructive" : "";

  const tc = useTableControls(data, PROD_SEARCH, PROD_SORT);

  // Kategori dari ref table + existing (backward compat)
  const allCategories = Array.from(new Set([
    ...refCats.filter(r => r.active).map(r => r.name),
    ...data.map(p => p.category).filter(Boolean) as string[],
  ])).sort();

  // ── Open form ────────────────────────────────────────────────────────────────
  function openAdd() {
    setForm(empty); setFormLineIds([]); setErrors({}); setOpen(true);
  }
  function openEdit(p: Product) {
    setForm(p); setFormLineIds(productLineMap.get(p.id) ?? []); setErrors({}); setOpen(true);
  }

  function toggleLine(lineId: string) {
    setFormLineIds(prev => prev.includes(lineId) ? prev.filter(id => id !== lineId) : [...prev, lineId]);
  }

  // ── Save product + product_lines ─────────────────────────────────────────────
  async function handleSave() {
    const newErr: Record<string, string> = {};
    if (!form.code?.trim()) newErr.code = "Kode wajib diisi";
    if (!form.name?.trim()) newErr.name = "Nama Produk wajib diisi";
    if (Object.keys(newErr).length > 0) { setErrors(newErr); return; }

    setSaveBusy(true);
    try {
      const result = await upsert.mutateAsync({
        ...form,
        code:        form.code!.trim().toUpperCase(),
        category:    form.category?.trim() || null,
        description: form.description?.trim() || null,
      });
      const productId: string = (result as any)?.id ?? form.id;

      if (productId) {
        const currentLineIds = productLineMap.get(productId) ?? [];
        const nextLineIds = Array.from(new Set(formLineIds));
        const toInsert = nextLineIds.filter(lineId => !currentLineIds.includes(lineId));
        const toDelete = currentLineIds.filter(lineId => !nextLineIds.includes(lineId));

        if (toInsert.length > 0) {
          const { error } = await (supabase.from("product_lines") as any)
            .insert(toInsert.map(lineId => ({ product_id: productId, line_id: lineId })));
          if (error) throw new Error(error.message);
        }
        if (toDelete.length > 0) {
          const { error } = await (supabase.from("product_lines") as any)
            .delete()
            .eq("product_id", productId)
            .in("line_id", toDelete);
          if (error) throw new Error(error.message);
        }
        qc.invalidateQueries({ queryKey: ["product-lines"] });
      }
      setOpen(false);
    } catch (e) {
      toast.error(e instanceof Error ? e.message : "Gagal menyimpan produk");
    } finally {
      setSaveBusy(false);
    }
  }

  // ── CSV import ────────────────────────────────────────────────────────────────
  const importProducts = async (rows: Record<string, string>[]) => {
    const toInsert = rows
      .filter(r => r.code?.trim() && r.name?.trim())
      .map(r => ({
        code:        r.code.trim().toUpperCase(),
        name:        r.name.trim(),
        model:       r.model?.trim() || null,
        category:    r.category?.trim() || null,
        description: r.description?.trim() || null,
        active:      toBool(r.active),
      }));
    if (!toInsert.length) return { imported: 0, errors: ["Tidak ada baris valid (code & name wajib)"] };
    const { data: imported, error } = await (supabase.from("products") as any)
      .upsert(toInsert, { onConflict: "code" }).select();
    if (error) throw new Error(error.message);
    return { imported: (imported ?? []).length, errors: [] as string[] };
  };

  // ── Render ────────────────────────────────────────────────────────────────────
  return (
    <>
      <AdminSection
        title="Master Produk"
        description="Katalog produk yang diproduksi, beserta lini produksi yang bisa membuatnya"
        onAdd={openAdd}
        rightSlot={
          <CsvButtons
            templateFilename="template-products.csv"
            templateHeaders={["code","name","model","category","description","active"]}
            templateSample={["PRD-001","CCU Motor A","X100","CCU","Produk CCU untuk motor type A","true"]}
            onImport={importProducts}
          />
        }
      >
        <TableToolbar
          search={tc.search} onSearch={tc.setSearch}
          total={tc.total} filteredCount={tc.filteredCount}
          activeFilterCount={tc.activeFilterCount} onClearColFilters={tc.clearColFilters}
        />

        {isLoading ? (
          <div className="text-sm text-muted-foreground p-4">Memuat…</div>
        ) : (
          <>
            <SortableDataTable
              cols={PROD_COLS}
              sortIdx={tc.sortIdx} onSort={tc.setSortIdx}
              colFilters={tc.colFilters} onColFilter={tc.setColFilter}
            >
              {tc.paged.map(p => {
                const assignedLines = (productLineMap.get(p.id) ?? [])
                  .map(lid => lineById.get(lid))
                  .filter(Boolean) as Line[];

                return (
                  <tr key={p.id} className="border-b hover:bg-surface-2">
                    <td className="px-3 py-2 font-mono text-xs font-semibold">{p.code}</td>
                    <td className="px-3 py-2">
                      {p.category
                        ? <span className={categoryChip(p.category)}>{p.category}</span>
                        : <span className="text-muted-foreground/60 text-xs">—</span>}
                    </td>
                    <td className="px-3 py-2 font-medium">{p.name}</td>
                    <td className="px-3 py-2 font-mono text-xs text-muted-foreground">{p.model ?? "—"}</td>
                    <td className="px-3 py-2">
                      {assignedLines.length === 0 ? (
                        <span className="text-muted-foreground/50 text-xs italic">—</span>
                      ) : (
                        <div className="flex flex-wrap gap-1">
                          {assignedLines.map(l => (
                            <span key={l.id} className="chip chip-info font-mono text-[10px] px-1.5 py-0.5">
                              {l.code}
                            </span>
                          ))}
                        </div>
                      )}
                    </td>
                    <td className="px-3 py-2">
                      <span className={p.active ? "chip chip-success" : "chip chip-warning"}>
                        {p.active ? "Aktif" : "Non-aktif"}
                      </span>
                    </td>
                    <td className="px-3 py-2">
                      <RowActions>
                        <Button size="icon" variant="ghost" onClick={() => openEdit(p)}>
                          <Pencil className="h-3.5 w-3.5" />
                        </Button>
                        <Button size="icon" variant="ghost"
                          onClick={() => confirm(`Hapus produk ${p.code}?`) && del.mutate(p.id)}>
                          <Trash2 className="h-3.5 w-3.5 text-destructive" />
                        </Button>
                      </RowActions>
                    </td>
                  </tr>
                );
              })}
              {tc.paged.length === 0 && (
                <tr>
                  <td colSpan={7} className="text-center py-6 text-muted-foreground text-sm">
                    {tc.search || tc.activeFilterCount > 0 ? "Tidak ada hasil" : "Belum ada produk"}
                  </td>
                </tr>
              )}
            </SortableDataTable>

            <Pager
              page={tc.page} totalPages={tc.totalPages} onChange={tc.setPage}
              filteredCount={tc.filteredCount} total={tc.total}
              pageSize={tc.pageSize} onPageSizeChange={tc.setPageSize}
            />
          </>
        )}
      </AdminSection>

      {/* ── Form Modal ──────────────────────────────────────────────────────── */}
      <FormModal
        open={open} onOpenChange={setOpen}
        title={form.id ? "Edit Produk" : "Tambah Produk"}
        onSubmit={handleSave}
        busy={saveBusy}
      >
        {/* Kode + Nama */}
        <div className="grid grid-cols-2 gap-3">
          <div className="space-y-1.5">
            <Label>Kode <span className="text-destructive">*</span></Label>
            <Input
              value={form.code ?? ""} placeholder="PRD-001" className={errCls("code")}
              onChange={e => { clearErr("code"); setForm(f => ({ ...f, code: e.target.value.toUpperCase() })); }}
            />
            {errors.code && <p className="text-[11px] text-destructive">{errors.code}</p>}
          </div>
          <div className="space-y-1.5">
            <Label>Nama <span className="text-destructive">*</span></Label>
            <Input
              value={form.name ?? ""} placeholder="CCU Motor A" className={errCls("name")}
              onChange={e => { clearErr("name"); setForm(f => ({ ...f, name: e.target.value })); }}
            />
            {errors.name && <p className="text-[11px] text-destructive">{errors.name}</p>}
          </div>
        </div>

        {/* Model + Kategori */}
        <div className="grid grid-cols-2 gap-3">
          <div className="space-y-1.5">
            <Label>Model</Label>
            <Input value={form.model ?? ""} placeholder="X100"
              onChange={e => setForm(f => ({ ...f, model: e.target.value }))} />
          </div>
          <div className="space-y-1.5">
            <Label>Kategori</Label>
            <Input list="product-categories" value={form.category ?? ""} placeholder="Pilih atau ketik…"
              onChange={e => setForm(f => ({ ...f, category: e.target.value }))} />
            <datalist id="product-categories">
              {allCategories.map(c => <option key={c} value={c} />)}
            </datalist>
          </div>
        </div>

        {/* Lini Produksi — multi-select checkboxes */}
        <div className="space-y-2">
          <div>
            <Label>Lini Produksi</Label>
            <p className="text-[11px] text-muted-foreground mt-0.5">
              Pilih lini yang dapat memproduksi produk ini. Bisa lebih dari satu.
            </p>
          </div>
          {lines.length === 0 ? (
            <p className="text-xs text-muted-foreground italic px-1">
              Belum ada data lini — tambahkan terlebih dahulu di tab Lini Produksi.
            </p>
          ) : (
            <div className="grid grid-cols-2 gap-1.5 max-h-44 overflow-y-auto rounded-lg border p-2 bg-slate-50/80">
              {lines.map(line => {
                const checked = formLineIds.includes(line.id);
                return (
                  <label
                    key={line.id}
                    className={`flex items-center gap-2 rounded-lg border px-2.5 py-2 cursor-pointer transition-colors ${
                      checked ? "border-primary/60 bg-blue-50 text-primary" : "border-border bg-white hover:bg-slate-100"
                    }`}
                  >
                    <input
                      type="checkbox"
                      checked={checked}
                      onChange={() => toggleLine(line.id)}
                      className="h-3.5 w-3.5 accent-primary shrink-0"
                    />
                    <span className="font-mono text-[11px] font-bold shrink-0">{line.code}</span>
                    <span className="text-xs text-muted-foreground truncate">{line.name}</span>
                  </label>
                );
              })}
            </div>
          )}
          {formLineIds.length > 0 && (
            <p className="text-[11px] text-primary font-medium">
              ✓ {formLineIds.length} lini dipilih:{" "}
              {formLineIds.map(id => lineById.get(id)?.code).filter(Boolean).join(", ")}
            </p>
          )}
        </div>

        {/* Deskripsi */}
        <div className="space-y-1.5">
          <Label>Deskripsi</Label>
          <Textarea value={form.description ?? ""} placeholder="Deskripsi singkat produk…"
            onChange={e => setForm(f => ({ ...f, description: e.target.value }))} />
        </div>

        {/* Aktif */}
        <div className="flex items-center justify-between">
          <Label className="m-0">Aktif</Label>
          <Switch checked={form.active ?? true} onCheckedChange={v => setForm(f => ({ ...f, active: v }))} />
        </div>
      </FormModal>
    </>
  );
}

import { Component, ErrorInfo, ReactNode } from "react";
import { AlertTriangle, RefreshCw, Home } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";

interface Props {
  children: ReactNode;
  fallback?: ReactNode;
  onError?: (error: Error, errorInfo: ErrorInfo) => void;
  component?: string;
}

interface State {
  hasError: boolean;
  error: Error | null;
  errorInfo: ErrorInfo | null;
  errorId: string;
}

export class MonitoringErrorBoundary extends Component<Props, State> {
  constructor(props: Props) {
    super(props);
    this.state = {
      hasError: false,
      error: null,
      errorInfo: null,
      errorId: "",
    };
  }

  static getDerivedStateFromError(error: Error): Partial<State> {
    return {
      hasError: true,
      error,
      errorId: `error-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
    };
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    this.setState({
      error,
      errorInfo,
    });

    // Log error to console in development
    if (process.env.NODE_ENV === "development") {
      console.error("Monitoring Error Boundary caught an error:", error, errorInfo);
    }

    // Call custom error handler if provided
    this.props.onError?.(error, errorInfo);

    // In production, you might want to send this to an error reporting service
    if (process.env.NODE_ENV === "production") {
      // Example: Sentry.captureException(error, { extra: errorInfo });
    }
  }

  handleRetry = () => {
    this.setState({
      hasError: false,
      error: null,
      errorInfo: null,
      errorId: "",
    });
  };

  handleGoHome = () => {
    window.location.href = "/";
  };

  render() {
    if (this.state.hasError) {
      // Custom fallback UI
      if (this.props.fallback) {
        return this.props.fallback;
      }

      // Default error UI
      return (
        <div className="min-h-screen flex items-center justify-center bg-background p-4">
          <Card className="max-w-md w-full p-6 space-y-4">
            <div className="flex items-center gap-3 text-destructive">
              <AlertTriangle className="h-6 w-6" />
              <h2 className="text-lg font-semibold">Monitoring Error</h2>
            </div>

            <div className="space-y-2">
              <p className="text-sm text-muted-foreground">
                Something went wrong while loading the monitoring dashboard.
              </p>

              <div className="flex items-center gap-2">
                <Badge variant="secondary" className="text-xs">
                  {this.props.component || "Unknown Component"}
                </Badge>
                <Badge variant="outline" className="text-xs font-mono">
                  {this.state.errorId}
                </Badge>
              </div>
            </div>

            {process.env.NODE_ENV === "development" && this.state.error && (
              <details className="mt-4">
                <summary className="text-sm font-medium cursor-pointer text-muted-foreground hover:text-foreground">
                  Error Details (Development Only)
                </summary>
                <div className="mt-2 p-3 bg-muted rounded-md">
                  <pre className="text-xs overflow-auto max-h-32">
                    {this.state.error.toString()}
                    {this.state.errorInfo && (
                      <div className="mt-2">
                        <strong>Component Stack:</strong>
                        <br />
                        {this.state.errorInfo.componentStack}
                      </div>
                    )}
                  </pre>
                </div>
              </details>
            )}

            <div className="flex gap-2 pt-4">
              <Button onClick={this.handleRetry} className="flex-1 gap-2">
                <RefreshCw className="h-4 w-4" />
                Try Again
              </Button>
              <Button variant="outline" onClick={this.handleGoHome} className="gap-2">
                <Home className="h-4 w-4" />
                Home
              </Button>
            </div>
          </Card>
        </div>
      );
    }

    return this.props.children;
  }
}

/**
 * HOC for wrapping components with error boundary
 */
export function withMonitoringErrorBoundary<P extends object>(
  Component: React.ComponentType<P>,
  options?: { fallback?: ReactNode; component?: string }
) {
  return function WrappedComponent(props: P) {
    return (
      <MonitoringErrorBoundary
        component={options?.component}
        fallback={options?.fallback}
      >
        <Component {...props} />
      </MonitoringErrorBoundary>
    );
  };
}

/**
 * Simple error boundary for individual panels
 */
export function PanelErrorBoundary({ 
  children, 
  title = "Panel",
  onRetry 
}: { 
  children: ReactNode;
  title?: string;
  onRetry?: () => void;
}) {
  return (
    <MonitoringErrorBoundary
      component={title}
      fallback={
        <Card className="p-4 text-center">
          <AlertTriangle className="h-8 w-8 text-muted-foreground mx-auto mb-2" />
          <h3 className="text-sm font-medium text-foreground mb-1">
            {title} Error
          </h3>
          <p className="text-xs text-muted-foreground mb-3">
            Unable to load {title.toLowerCase()} data
          </p>
          <Button size="sm" onClick={onRetry} className="gap-1">
            <RefreshCw className="h-3 w-3" />
            Retry
          </Button>
        </Card>
      }
    >
      {children}
    </MonitoringErrorBoundary>
  );
}

import { useState, useEffect } from "react";
import { Wifi, WifiOff, RefreshCw, AlertTriangle } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { cn } from "@/lib/utils";
import { toast } from "sonner";

interface OfflineIndicatorProps {
  /** Position of the indicator */
  position?: "top-right" | "top-left" | "bottom-right" | "bottom-left";
  /** Whether to show detailed status */
  detailed?: boolean;
  /** Custom class names */
  className?: string;
  /** Callback when connection is restored */
  onConnectionRestored?: () => void;
  /** Callback when connection is lost */
  onConnectionLost?: () => void;
}

interface ConnectionState {
  isOnline: boolean;
  isSlow: boolean;
  lastConnected: Date | null;
  reconnectAttempts: number;
  connectionType: string;
}

export function OfflineIndicator({ 
  position = "top-right",
  detailed = false,
  className,
  onConnectionRestored,
  onConnectionLost
}: OfflineIndicatorProps) {
  const [connectionState, setConnectionState] = useState<ConnectionState>({
    isOnline: navigator.onLine,
    isSlow: false,
    lastConnected: null,
    reconnectAttempts: 0,
    connectionType: 'unknown'
  });
  const [isReconnecting, setIsReconnecting] = useState(false);

  const positionClasses = {
    "top-right": "fixed top-4 right-4 z-50",
    "top-left": "fixed top-4 left-4 z-50", 
    "bottom-right": "fixed bottom-4 right-4 z-50",
    "bottom-left": "fixed bottom-4 left-4 z-50"
  };

  // Monitor connection status
  useEffect(() => {
    const handleOnline = () => {
      setConnectionState(prev => ({
        ...prev,
        isOnline: true,
        lastConnected: new Date(),
        reconnectAttempts: 0
      }));

      toast.success("Koneksi terhubung kembali");
      onConnectionRestored?.();
    };

    const handleOffline = () => {
      setConnectionState(prev => ({
        ...prev,
        isOnline: false,
        lastConnected: new Date()
      }));

      toast.error("Koneksi terputus");
      onConnectionLost?.();
    };

    const checkConnectionSpeed = async () => {
      if (!navigator.onLine) return;

      try {
        const start = performance.now();
        await fetch('/api/health', { method: 'HEAD' });
        const duration = performance.now() - start;

        setConnectionState(prev => ({
          ...prev,
          isSlow: duration > 3000, // Consider slow if > 3 seconds
          connectionType: (navigator as any).connection ? (navigator as any).connection.effectiveType || 'unknown' : 'unknown'
        }));
      } catch {
        setConnectionState(prev => ({
          ...prev,
          isSlow: true
        }));
      }
    };

    // Initial check
    checkConnectionSpeed();

    // Set up event listeners
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    // Periodic connection speed check
    const speedCheckInterval = setInterval(checkConnectionSpeed, 30000);

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
      clearInterval(speedCheckInterval);
    };
  }, [onConnectionRestored, onConnectionLost]);

  // Auto-reconnect logic
  useEffect(() => {
    if (!connectionState.isOnline && connectionState.reconnectAttempts < 5) {
      const timeout = setTimeout(() => {
        setIsReconnecting(true);

        // Try to reconnect
        if (navigator.onLine) {
          fetch('/api/health', { method: 'HEAD' })
            .then(() => {
              setConnectionState(prev => ({
                ...prev,
                isOnline: true,
                lastConnected: new Date(),
                reconnectAttempts: 0
              }));
            })
            .catch(() => {
              setConnectionState(prev => ({
                ...prev,
                reconnectAttempts: prev.reconnectAttempts + 1
              }));
            })
            .finally(() => {
              setIsReconnecting(false);
            });
        }
      }, Math.pow(2, connectionState.reconnectAttempts) * 1000); // Exponential backoff

      return () => clearTimeout(timeout);
    }
  }, [connectionState.isOnline, connectionState.reconnectAttempts]);

  const handleManualReconnect = async () => {
    setIsReconnecting(true);

    try {
      await fetch('/api/health', { method: 'HEAD' });
      setConnectionState(prev => ({
        ...prev,
        isOnline: true,
        lastConnected: new Date(),
        reconnectAttempts: 0
      }));
      toast.success("Koneksi berhasil dipulihkan");
    } catch {
      setConnectionState(prev => ({
        ...prev,
        reconnectAttempts: prev.reconnectAttempts + 1
      }));
      toast.error("Gagal terhubung ke server");
    } finally {
      setIsReconnecting(false);
    }
  };

  const formatLastConnected = (date: Date | null) => {
    if (!date) return "Tidak pernah terhubung";

    const now = new Date();
    const diffMs = now.getTime() - date.getTime();
    const diffMins = Math.floor(diffMs / 60000);

    if (diffMins < 1) return "Baru saja";
    if (diffMins < 60) return `${diffMins} menit lalu`;

    const diffHours = Math.floor(diffMins / 60);
    if (diffHours < 24) return `${diffHours} jam lalu`;

    const diffDays = Math.floor(diffHours / 24);
    return `${diffDays} hari lalu`;
  };

  if (connectionState.isOnline && !connectionState.isSlow && !detailed) {
    return null; // Don't show indicator when everything is fine
  }

  return (
    <div className={cn(
      "bg-card border rounded-lg shadow-lg p-3 max-w-sm",
      positionClasses[position],
      className
    )}>
      <div className="flex items-center gap-3">
        <div className="flex items-center gap-2">
          {connectionState.isOnline ? (
            connectionState.isSlow ? (
              <AlertTriangle className="h-5 w-5 text-yellow-500" />
            ) : (
              <Wifi className="h-5 w-5 text-green-500" />
            )
          ) : (
            <WifiOff className="h-5 w-5 text-red-500" />
          )}

          <div className="flex flex-col">
            <span className="text-sm font-medium">
              {connectionState.isOnline ? (
                connectionState.isSlow ? "Koneksi Lambat" : "Tersambung"
              ) : "Offline"}
            </span>

            {detailed && (
              <span className="text-xs text-muted-foreground">
                {connectionState.connectionType} • 
                Terakhir: {formatLastConnected(connectionState.lastConnected)}
              </span>
            )}
          </div>
        </div>

        <div className="flex items-center gap-2 ml-auto">
          {connectionState.isSlow && (
            <Badge variant="secondary" className="text-xs">
              Lambat
            </Badge>
          )}

          {!connectionState.isOnline && (
            <Button
              size="sm"
              onClick={handleManualReconnect}
              disabled={isReconnecting}
              className="gap-1"
            >
              {isReconnecting ? (
                <RefreshCw className="h-3 w-3 animate-spin" />
              ) : (
                <RefreshCw className="h-3 w-3" />
              )}
              {isReconnecting ? "Menghubungkan..." : "Hubungkan"}
            </Button>
          )}
        </div>
      </div>

      {detailed && !connectionState.isOnline && connectionState.reconnectAttempts > 0 && (
        <div className="mt-2 text-xs text-muted-foreground">
          Percobaan ke-{connectionState.reconnectAttempts} dari 5
        </div>
      )}
    </div>
  );
}

/**
 * Hook for connection status monitoring
 */
export function useConnectionStatus() {
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const isSlow = false;

  useEffect(() => {
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  return { isOnline, isSlow };
}

/**
 * Simple connection status badge
 */
export function ConnectionStatusBadge() {
  const { isOnline, isSlow } = useConnectionStatus();

  if (!isOnline) {
    return (
      <Badge variant="destructive" className="gap-1">
        <WifiOff className="h-3 w-3" />
        Offline
      </Badge>
    );
  }

  if (isSlow) {
    return (
      <Badge variant="secondary" className="gap-1">
        <AlertTriangle className="h-3 w-3" />
        Lambat
      </Badge>
    );
  }

  return (
    <Badge variant="default" className="gap-1 bg-green-100 text-green-800">
      <Wifi className="h-3 w-3" />
      Online
    </Badge>
  );
}

