          <div className="space-y-2">
            <div className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
              <span className="text-sm">Target set to 150 pcs</span>
              <span className="text-xs text-gray-500">2 min ago</span>
            </div>
            <div className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
              <span className="text-sm">Operator assigned</span>
              <span className="text-xs text-gray-500">5 min ago</span>
            </div>
          </div>
        </div>
      </div>
    </BottomSheet>
  );

  // Mobile layout
  if (layout.isMobile) {
    return (
      <div className="flex flex-col h-screen bg-gray-50">
        {/* Mobile Header */}
        <div className="bg-white border-b">
          <div className="flex items-center justify-between p-4">
            <Button variant="ghost" size="sm">
              <Menu className="h-5 w-5" />
            </Button>
            <h1 className="font-semibold">Input Laporan</h1>
            <Button variant="ghost" size="sm">
              <HelpCircle className="h-5 w-5" />
            </Button>
          </div>
          <StepNavigation />
        </div>

        {/* Main Content */}
        <ContentArea />

        {/* Bottom Sheet */}
        <BottomSheetComponent />

        {/* Floating Action Button */}
        <FloatingActionButton />
      </div>
    );
  }

  // Tablet layout
  if (layout.isTablet) {
    return (
      <div className="flex h-screen bg-gray-50">
        {/* Sidebar */}
        <div className="w-64 bg-white border-r p-4">
          <h2 className="font-semibold mb-4">Steps</h2>
          <div className="space-y-2">
            {[1, 2, 3, 4, 5, 6, 7].map((step) => (
              <Button
                key={step}
                variant={currentStep + 1 === step ? "default" : "ghost"}
                className="w-full justify-start"
                onClick={() => setCurrentStep(step - 1)}
              >
                Step {step}
              </Button>
            ))}
          </div>
        </div>

        {/* Main Content */}
        <div className="flex-1 flex flex-col">
          <StepNavigation />
          <ContentArea />
        </div>
      </div>
    );
  }

  // Desktop layout (fallback)
  return (
    <div className="container mx-auto p-6">
      <div className="bg-yellow-50 border border-yellow-200 rounded-lg p-4">
        <p className="text-yellow-800">
          This component is optimized for mobile and tablet devices.
        </p>
      </div>
    </div>
  );
}

/**
 * Touch-friendly form component
 */
export function TouchOptimizedInput({ 
  label, 
  type = 'text', 
  placeholder, 
  value, 
  onChange 
}: {
  label: string;
  type?: string;
  placeholder?: string;
  value?: string;
  onChange?: (value: string) => void;
}) {
  const [focused, setFocused] = useState(false);

  return (
    <div className="touch-manipulation">
      <label className="block text-sm font-medium mb-2">{label}</label>
      <input
        type={type}
        value={value}
        onChange={(e) => onChange?.(e.target.value)}
        onFocus={() => setFocused(true)}
        onBlur={() => setFocused(false)}
        placeholder={placeholder}
        className={cn(
          "w-full p-4 text-lg border-2 rounded-xl transition-all duration-200",
          "focus:ring-2 focus:ring-blue-500 focus:border-blue-500",
          focused ? "border-blue-500" : "border-gray-300"
        )}
        style={{ fontSize: '16px' }} // Prevents zoom on iOS
      />
    </div>
  );
}

/**
 * Swipeable card component for mobile
 */
export function SwipeableCard({ 
  children, 
  onSwipeLeft, 
  onSwipeRight 
}: {
  children: React.ReactNode;
  onSwipeLeft?: () => void;
  onSwipeRight?: () => void;
}) {
  const dragControls = useDragControls();

  return (
    <Swipeable
      onSwipeLeft={onSwipeLeft}
      onSwipeRight={onSwipeRight}
      className="touch-manipulation"
    >
      <motion.div
        drag="x"
        dragControls={dragControls}
        dragConstraints={{ left: 0, right: 0 }}
        dragElastic={0.2}
        className="bg-white rounded-xl shadow-sm border"
      >
        {children}
      </motion.div>
    </Swipeable>
  );
}

/**
 * Mobile-optimized button with haptic feedback
 */
export function MobileButton({ 
  children, 
  onClick, 
  variant = 'default',
  size = 'default',
  haptic = true
}: {
  children: React.ReactNode;
  onClick?: () => void;
  variant?: 'default' | 'outline' | 'ghost';
  size?: 'sm' | 'default' | 'lg';
  haptic?: boolean;
}) {
  const handleClick = () => {
    if (haptic && 'vibrate' in navigator) {
      navigator.vibrate(50); // Light haptic feedback
    }
    onClick?.();
  };

  const sizeClasses = {
    sm: 'p-3 text-sm',
    default: 'p-4 text-base',
    lg: 'p-6 text-lg'
  };

  return (
    <Button
      variant={variant}
      size={size}
      onClick={handleClick}
      className={cn(
        "touch-manipulation transition-all duration-200 active:scale-95",
        sizeClasses[size]
      )}
    >
      {children}
    </Button>
  );
}

