 */
export function TouchOptimizedInput({ 
  label, 
  type = 'text', 
  placeholder, 
  value, 
  onChange 
}: {
  label: string;
  type?: string;
  placeholder?: string;
  value?: string;
  onChange?: (value: string) => void;
}) {
  const [focused, setFocused] = useState(false);

  return (
    <div className="touch-manipulation">
      <label className="block text-sm font-medium mb-2">{label}</label>
      <input
        type={type}
        value={value}
