import { useMemo } from "react";
import { 
  Monitor, 
  Users, 
  CheckCircle, 
  AlertTriangle, 
  Shield,
  Clock,
  TrendingUp,
  Activity
} from "lucide-react";
import { Card } from "@/components/ui/card";
