export function useRealTimeUpdatesSimple({
  workspaceId,
  lineId,
  enableNotifications = true,
  reconnectAttempts = 5,
  reconnectDelay = 3000
}: UseRealTimeUpdatesOptions = {}): UseRealTimeUpdatesReturn {
  const [isConnected, setIsConnected] = useState(false);
  const [isConnecting, setIsConnecting] = useState(false);
  const [connectionStatus, setConnectionStatus] = useState<'connected' | 'connecting' | 'disconnected' | 'error'>('disconnected');
  const [lastUpdate, setLastUpdate] = useState<RealtimeUpdate | null>(null);
  const [systemAlerts, setSystemAlerts] = useState<SystemAlert[]>([]);
  const [recentUpdates, setRecentUpdates] = useState<RealtimeUpdate[]>([]);

  const wsRef = useRef<WebSocket | null>(null);
  const reconnectTimeoutRef = useRef<NodeJS.Timeout | null>(null);
  const reconnectAttemptsRef = useRef(0);
  const heartbeatIntervalRef = useRef<NodeJS.Timeout | null>(null);

  // WebSocket URL construction
  const getWebSocketUrl = useCallback(() => {
    const protocol = window.location.protocol === 'https:' ? 'wss:' : 'ws:';
    const host = window.location.host;
    const wsUrl = `${protocol}//${host}/api/ws/production-updates`;

    const params = new URLSearchParams();
    if (workspaceId) params.append('workspaceId', workspaceId);
    if (lineId) params.append('lineId', lineId);

    return `${wsUrl}?${params.toString()}`;
  }, [workspaceId, lineId]);

  // Handle incoming WebSocket messages
  const handleWebSocketMessage = useCallback((event: MessageEvent) => {
    try {
      const message = JSON.parse(event.data);

      switch (message.type) {
        case 'update':
          const update: RealtimeUpdate = message.data;
          setLastUpdate(update);
          setRecentUpdates(prev => [update, ...prev.slice(0, 49)]); // Keep last 50 updates

          // Show notification for important updates
          if (enableNotifications) {
            handleUpdateNotification(update);
          }
          break;

        case 'alert':
          const alert: SystemAlert = message.data;
          setSystemAlerts(prev => [alert, ...prev.slice(0, 9)]); // Keep last 10 alerts

          if (enableNotifications) {
            handleAlertNotification(alert);
          }
          break;

        case 'heartbeat':
          // Respond to server heartbeat
          if (wsRef.current) {
            wsRef.current.send(JSON.stringify({ type: 'heartbeat_response' }));
          }
          break;

        case 'ping':
          // Respond to ping
          if (wsRef.current) {
            wsRef.current.send(JSON.stringify({ type: 'pong' }));
          }
          break;

        default:
          console.warn('Unknown WebSocket message type:', message.type);
      }
    } catch (error) {
      console.error('Error parsing WebSocket message:', error);
    }
  }, [enableNotifications]);

  // Handle update notifications
  const handleUpdateNotification = useCallback((update: RealtimeUpdate) => {
    let message = '';

    switch (update.type) {
      case 'operator_status':
        message = `Operator status has been updated`;
        break;
      case 'skill_compliance':
        message = `Skill compliance status has changed`;
        break;
      case 'workstation_status':
        message = `Workstation status has been updated`;
        break;
      default:
        message = 'New update received';
    }

    toast.info(message, {
      description: new Date(update.timestamp).toLocaleTimeString('id-ID'),
      action: {
        label: 'View Details',
        onClick: () => console.log('View update details:', update.id)
      }
    });
  }, []);

  // Handle alert notifications
  const handleAlertNotification = useCallback((alert: SystemAlert) => {
    const toastFn = alert.type === 'error' ? toast.error :
                     alert.type === 'warning' ? toast.warning :
                     alert.type === 'success' ? toast.success : toast.info;

    toastFn(alert.message, {
      description: alert.title,
      duration: alert.type === 'error' ? 10000 : 5000,
      action: alert.requiresAction ? {
        label: 'Take Action',
        onClick: () => {
          if (alert.actionUrl) {
            window.location.href = alert.actionUrl;
          }
        }
      } : undefined
    });
  }, []);

  // Start heartbeat
  const startHeartbeat = useCallback(() => {
    if (heartbeatIntervalRef.current) {
      clearInterval(heartbeatIntervalRef.current);
    }

    heartbeatIntervalRef.current = setInterval(() => {
      if (wsRef.current && wsRef.current.readyState === WebSocket.OPEN) {
        wsRef.current.send(JSON.stringify({ type: 'heartbeat' }));
      }
    }, 30000); // Send heartbeat every 30 seconds
  }, []);

  // Stop heartbeat
  const stopHeartbeat = useCallback(() => {
    if (heartbeatIntervalRef.current) {
      clearInterval(heartbeatIntervalRef.current);
      heartbeatIntervalRef.current = null;
    }
  }, []);

  // Connect to WebSocket
  const connect = useCallback(() => {
    if (wsRef.current?.readyState === WebSocket.OPEN) {
      return;
    }

    setIsConnecting(true);
    setConnectionStatus('connecting');

    try {
      const ws = new WebSocket(getWebSocketUrl());
      wsRef.current = ws;

      ws.onopen = () => {
        console.log('WebSocket connected');
        setIsConnected(true);
        setIsConnecting(false);
        setConnectionStatus('connected');
        reconnectAttemptsRef.current = 0;
        startHeartbeat();

        toast.success('Real-time updates connected', {
          description: 'You will receive live updates now'
        });
      };

      ws.onmessage = handleWebSocketMessage;

      ws.onclose = (event) => {
        console.log('WebSocket disconnected:', event.code, event.reason);
        setIsConnected(false);
        setIsConnecting(false);
        setConnectionStatus('disconnected');
        stopHeartbeat();

        // Attempt reconnection if not a normal closure
        if (event.code !== 1000 && reconnectAttemptsRef.current < reconnectAttempts) {
          reconnectAttemptsRef.current++;
          console.log(`Attempting reconnection ${reconnectAttemptsRef.current}/${reconnectAttempts}`);

          reconnectTimeoutRef.current = setTimeout(() => {
            connect();
          }, reconnectDelay * reconnectAttemptsRef.current);
        } else if (reconnectAttemptsRef.current >= reconnectAttempts) {
          setConnectionStatus('error');
          toast.error('Connection lost', {
            description: 'Unable to reconnect to real-time updates'
          });
        }
      };

      ws.onerror = (error) => {
        console.error('WebSocket error:', error);
        setConnectionStatus('error');
        toast.error('Connection error', {
          description: 'Failed to establish real-time connection'
        });
      };

    } catch (error) {
      console.error('Failed to create WebSocket connection:', error);
      setIsConnecting(false);
      setConnectionStatus('error');
    }
  }, [getWebSocketUrl, handleWebSocketMessage, startHeartbeat, stopHeartbeat, reconnectAttempts, reconnectDelay]);

  // Disconnect from WebSocket
  const disconnect = useCallback(() => {
    if (reconnectTimeoutRef.current) {
      clearTimeout(reconnectTimeoutRef.current);
      reconnectTimeoutRef.current = null;
    }

    stopHeartbeat();

    if (wsRef.current) {
      wsRef.current.close(1000, 'User disconnected');
      wsRef.current = null;
    }

    setIsConnected(false);
    setIsConnecting(false);
    setConnectionStatus('disconnected');
  }, [stopHeartbeat]);

  // Manual refresh
  const manualRefresh = useCallback(() => {
    if (wsRef.current?.readyState === WebSocket.OPEN) {
      wsRef.current.send(JSON.stringify({ type: 'refresh_request' }));
    } else {
      connect();
    }
  }, [connect]);

  // Clear alerts
  const clearAlerts = useCallback(() => {
    setSystemAlerts([]);
  }, []);

  // Mark alert as read
  const markAlertAsRead = useCallback((alertId: string) => {
    setSystemAlerts(prev => prev.filter(alert => alert.id !== alertId));
  }, []);

  // Initialize connection
  useEffect(() => {
    connect();

    return () => {
      disconnect();
    };
  }, [connect, disconnect]);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      if (reconnectTimeoutRef.current) {
        clearTimeout(reconnectTimeoutRef.current);
      }
      stopHeartbeat();
    };
  }, [stopHeartbeat]);

  return {
    isConnected,
    isConnecting,
    lastUpdate,
    systemAlerts,
    recentUpdates,
    connectionStatus,
    manualRefresh,
    clearAlerts,
    markAlertAsRead
  };
}

/**
 * useShiftSetup — orchestration hook for the Setup Awal Production Run page.
 *
 * Owns all local UI state, derived state, effects, validation, and the
 * handleStartShift mutation.  The page component is left as a thin render layer.
 */

import { useEffect, useMemo, useState } from "react";
import { toast } from "sonner";
import { useAuth } from "@/contexts/AuthContext";
import { useActiveShiftRun, useCreateShiftRun } from "@/hooks/useShiftRun";
import {
  type ShiftTab,
  type SetupStep,
  type SampleCheck,
  type POSAssignment,
  type Step1State,
  STEP1_DEFAULT,
} from "../types";
import {
  useLines,
  useProducts,
  useAllShifts,
  useLeaderGroups,
  useLineProducts,
  useLineOperators,
  useLineGroups,
  useGroupPOS,
  useLineCheckItems,
} from "./useShiftSetupData";

// ─── Internal helpers ─────────────────────────────────────────────────────────

const toMins = (t: string) => {
  const [h, m] = t.split(":").map(Number);
  return h * 60 + (m || 0);
};

const combineDateTime = (dateStr: string, timeStr: string, refTimeStr?: string): string => {
  const d = new Date(`${dateStr}T${timeStr}:00`);
  if (refTimeStr && toMins(timeStr) < toMins(refTimeStr)) d.setDate(d.getDate() + 1);
  return d.toISOString();
};

const emptyChecks = (): SampleCheck[] =>
  Array.from({ length: 5 }, (_, i) => ({ no: i + 1, status: "" as const, measurement: "", note: "" }));

// ─── Hook ─────────────────────────────────────────────────────────────────────

export function useShiftSetup() {
  const { user } = useAuth();

  // ── Draft persistence key ───────────────────────────────────────────────────
  const draftKey = user?.id ? `shift_draft_v1_${user.id}` : null;
  const [draftRestored, setDraftRestored] = useState(false);

  // ── UI State ────────────────────────────────────────────────────────────────
  const [activeTab, setActiveTab]             = useState<ShiftTab>("setup");
  const [setupStep, setSetupStep]             = useState<SetupStep>(1);
  const [step1, setStep1]                     = useState<Step1State>(STEP1_DEFAULT);
  const [step1Errors, setStep1Errors]         = useState<Record<string, string>>({});
  const [checkedItems, setCheckedItems]       = useState<string[]>([]);
  const [posOpAssignments, setPosOpAssignments] = useState<Record<string, POSAssignment>>({});
  const [firstChecks, setFirstChecks]         = useState<SampleCheck[]>(emptyChecks());
  const [lastChecks, setLastChecks]           = useState<SampleCheck[]>(emptyChecks());
  const [firstCheckDone, setFirstCheckDone]   = useState(false);
  const [lastCheckDone, setLastCheckDone]     = useState(false);
  const [setupNotes, setSetupNotes]           = useState("");
  const [setupBusy, setSetupBusy]             = useState(false);

  // ── Server State ────────────────────────────────────────────────────────────
  const { data: activeRun, isLoading: runLoading } = useActiveShiftRun();

  const { data: lines = [],        isLoading: linesLoading       } = useLines();
  const { data: products = [],     isLoading: productsLoading    } = useProducts();
  const { data: allShifts = [],    isLoading: shiftsLoading      } = useAllShifts();
  const { data: leaderGroups = []                                 } = useLeaderGroups(user?.id);
  const { data: lineProducts = [], isLoading: lineProductsLoading } = useLineProducts(step1.lineId);

  const activeLineId  = step1.lineId  || activeRun?.line_id  || "";
  const activeGroupId = step1.groupId || "";

  const { data: lineOperators = []                               } = useLineOperators(activeLineId);
  const { data: lineGroups = [],    isLoading: groupsLoading     } = useLineGroups(activeLineId);
  const {
    data: groupPosResult = { groupId: null, groupCode: "", posData: [] },
    isLoading: posLoading,
  } = useGroupPOS(activeGroupId);

  const linePOS           = groupPosResult.posData;
  const resolvedGroupId   = step1.groupId || null;
  const resolvedGroupCode = lineGroups.find((g: any) => g.id === step1.groupId)?.code ?? "";

  const checkGroups = useLineCheckItems(step1.lineId);
  const totalChecks = checkGroups.reduce((sum, g) => sum + g.items.length, 0);

  // ── Derived state ────────────────────────────────────────────────────────────
  const leaderLineIds = useMemo(
    () => [
      ...new Set(
        leaderGroups
          .map((lg: any) => lg.groups?.line_id)
          .filter((id: any): id is string => !!id),
      ),
    ],
    [leaderGroups],
  );

  const visibleLines = useMemo(
    () => (leaderLineIds.length > 0 ? lines.filter(l => leaderLineIds.includes(l.id)) : lines),
    [lines, leaderLineIds],
  );

  // ── Effects ──────────────────────────────────────────────────────────────────

  // Auto-select line when leader has exactly one assigned line
  useEffect(() => {
    if (step1.lineId || visibleLines.length !== 1) return;
    setStep1(f => ({ ...f, lineId: visibleLines[0].id }));
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [visibleLines]);

  // Auto-select leader's group when line changes
  useEffect(() => {
    if (!step1.lineId || leaderGroups.length === 0) return;
    const match = leaderGroups.find((lg: any) => lg.groups?.line_id === step1.lineId);
    if (match) setStep1(f => ({ ...f, groupId: match.group_id }));
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [step1.lineId, leaderGroups]);

  // Auto-fill plan times from shift
  useEffect(() => {
    if (!step1.shiftId || allShifts.length === 0) return;
    const sel = allShifts.find(s => s.id === step1.shiftId);
    if (!sel) return;
    setStep1(f => ({
      ...f,
      planStartTime:   sel.start_time.slice(0, 5),
      planFinishTime:  sel.end_time.slice(0, 5),
      actualStartTime: sel.start_time.slice(0, 5),
    }));
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [step1.shiftId, allShifts]);

  // Restore draft from localStorage once run-loading settles
  useEffect(() => {
    if (runLoading || draftRestored || !draftKey) return;
    if (activeRun) { setDraftRestored(true); return; }
    try {
      const raw = localStorage.getItem(draftKey);
      if (!raw) { setDraftRestored(true); return; }
      const draft = JSON.parse(raw) as Record<string, unknown>;
      if (draft.savedAt && Date.now() - new Date(draft.savedAt as string).getTime() > 86_400_000) {
        localStorage.removeItem(draftKey);
        setDraftRestored(true);
        return;
      }
      if (draft.step1)              setStep1(draft.step1 as Step1State);
      if (draft.setupStep)          setSetupStep(draft.setupStep as SetupStep);
      if (draft.setupNotes != null) setSetupNotes(draft.setupNotes as string);
      if (draft.checkedItems)       setCheckedItems(draft.checkedItems as string[]);
      if (draft.firstChecks)        setFirstChecks(draft.firstChecks as SampleCheck[]);
      if (draft.lastChecks)         setLastChecks(draft.lastChecks as SampleCheck[]);
      if (draft.firstCheckDone != null) setFirstCheckDone(draft.firstCheckDone as boolean);
      if (draft.lastCheckDone  != null) setLastCheckDone(draft.lastCheckDone as boolean);
      if (draft.posOpAssignments)   setPosOpAssignments(draft.posOpAssignments as Record<string, POSAssignment>);
      toast.info("Draft form dipulihkan dari sesi sebelumnya.", { duration: 4000 });
    } catch {
      localStorage.removeItem(draftKey);
    } finally {
      setDraftRestored(true);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [runLoading, activeRun, draftKey]);

  // Persist draft on every relevant state change
  useEffect(() => {
    if (!draftKey || !draftRestored || activeRun) return;
    const draft = {
      step1, setupStep, setupNotes, checkedItems,
      firstChecks, lastChecks, firstCheckDone, lastCheckDone,
      posOpAssignments, savedAt: new Date().toISOString(),
    };
    localStorage.setItem(draftKey, JSON.stringify(draft));
  }, [
    draftKey, draftRestored, activeRun,
    step1, setupStep, setupNotes, checkedItems,
    firstChecks, lastChecks, firstCheckDone, lastCheckDone,
    posOpAssignments,
  ]);

  // ── Mutations ────────────────────────────────────────────────────────────────
  const createRun = useCreateShiftRun();

  // ── Validation ───────────────────────────────────────────────────────────────
  const clearE = (k: string) =>
    setStep1Errors(prev => { const n = { ...prev }; delete n[k]; return n; });

  function validateStep1(): boolean {
    const e: Record<string, string> = {};
    if (!step1.workOrderNo.trim()) e.workOrderNo = "No. Work Order wajib diisi";
    if (!step1.shiftId)            e.shiftId     = "Pilih shift terlebih dahulu";
    if (!step1.prodDate)           e.prodDate    = "Tanggal produksi wajib diisi";
    if (!step1.lineId)             e.lineId      = "Pilih lini produksi";
    if (!step1.groupId)            e.groupId     = "Pilih group / regu";
    if (!step1.productId)          e.productId   = "Pilih produk yang akan diproduksi";
    if (step1.targetQty <= 0)      e.targetQty   = "Rencana Qty harus lebih dari 0";
    setStep1Errors(e);
    if (Object.keys(e).length > 0) {
      toast.error("Lengkapi semua field wajib di Step 1.", { duration: 3000 });
    }
    return Object.keys(e).length === 0;
  }

  // ── handleStartShift ─────────────────────────────────────────────────────────
  const handleStartShift = async () => {
    if (!validateStep1()) return;
    setSetupBusy(true);
    try {
      const sel = allShifts.find((s: any) => s.id === step1.shiftId);
      const planStartStr = step1.planStartTime || (sel?.start_time?.slice(0, 5) ?? "");

      const shiftMins = sel
        ? (() => { const d = toMins(sel.end_time) - toMins(sel.start_time); return d > 0 ? d : d + 1440; })()
        : 480;
      const breakMins      = (sel as any)?.break_minutes ?? 60;
      const productiveMins = Math.max(60, shiftMins - breakMins);
      const hourlyTarget   = Math.round(step1.targetQty / (productiveMins / 60));

      const planStartAt  = planStartStr
        ? new Date(`${step1.prodDate}T${planStartStr}:00`).toISOString()
        : undefined;
      const planFinishAt = step1.planFinishTime
        ? combineDateTime(step1.prodDate, step1.planFinishTime, planStartStr || undefined)
        : undefined;
      const startedAt = step1.actualStartTime
        ? combineDateTime(step1.prodDate, step1.actualStartTime, planStartStr || undefined)
        : new Date().toISOString();

      await createRun.mutateAsync({
        line_id:             step1.lineId,
        shift_id:            step1.shiftId,
        group_id:            step1.groupId,
        product_id:          step1.productId,
        work_order_no:       step1.workOrderNo.trim(),
        target_quantity:     step1.targetQty,
        hourly_target:       hourlyTarget,
        leader_user_id:      user?.id || "",
        operator_ids:        [],
        checklist_completed: checkedItems.length === totalChecks,
        notes:               setupNotes.trim() || "",
        actual_started_at:   startedAt,
        plan_start_at:       planStartAt,
        plan_finish_at:      planFinishAt,
      });

      if (draftKey) localStorage.removeItem(draftKey);
      setSetupStep(1);
      setActiveTab("first_check");
      toast.success(`Shift run dimulai — WO ${step1.workOrderNo}`);
    } catch (e) {
      toast.error(e instanceof Error ? e.message : "Gagal memulai shift run.");
    } finally {
      setSetupBusy(false);
    }
  };

  // ── Exposed API ──────────────────────────────────────────────────────────────
  return {
    // auth / run
    user,
    activeRun,
    runLoading,

    // tabs / steps
    activeTab,  setActiveTab,
    setupStep,  setSetupStep,

    // step 1 form
    step1,       setStep1,
    step1Errors, clearE,
    validateStep1,

    // step 2
    posOpAssignments, setPosOpAssignments,
    linePOS,          posLoading,
    resolvedGroupId,  resolvedGroupCode,
    lineOperators,

    // step 3
    checkedItems, setCheckedItems,
    checkGroups,  totalChecks,

    // step 4 / notes
    setupNotes, setSetupNotes,
    setupBusy,
    createRun,
    handleStartShift,

    // sample checks (first / last)
    firstChecks,     setFirstChecks,
    lastChecks,      setLastChecks,
    firstCheckDone,  setFirstCheckDone,
    lastCheckDone,   setLastCheckDone,

    // master data
    lines,           linesLoading,
    products,        productsLoading,
    allShifts,       shiftsLoading,
    leaderGroups,
    lineProducts,    lineProductsLoading,
    lineGroups,      groupsLoading,
    visibleLines,
  };
}

/**
 * Domain data hooks for the Shift Setup feature.
 * Pure server-state queries — no local UI state.
 */

import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { FALLBACK_CHECK_GROUPS } from "../types";

// ─── Master data ──────────────────────────────────────────────────────────────

export function useLines() {
  return useQuery({
    queryKey: ["lines"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("lines")
        .select("id, code, name, active")
        .eq("active", true)
        .order("code");
      if (error) throw error;
      return data ?? [];
    },
  });
}

export function useProducts() {
  return useQuery({
    queryKey: ["products"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("products")
        .select("id, code, name, model")
        .eq("active", true)
        .order("code");
      if (error) throw error;
      return data ?? [];
    },
  });
}

export function useAllShifts() {
  return useQuery({
    queryKey: ["shifts"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("shifts")
        .select("*")
        .order("start_time");
      if (error) throw error;
      return data ?? [];
    },
  });
}

// ─── Leader-scoped data ───────────────────────────────────────────────────────

export function useLeaderGroups(userId?: string) {
  return useQuery({
    queryKey: ["leader_groups", userId],
    queryFn: async () => {
      if (!userId) return [];
      try {
        const { data: basicData, error: basicError } = await (supabase.from("group_leaders" as any) as any)
          .select("id, group_id")
          .eq("user_id", userId);
        if (basicError) throw basicError;
        if (!basicData || basicData.length === 0) return [];

        const groupIds = basicData.map((gl: any) => gl.group_id).filter(Boolean);
        if (groupIds.length === 0) return basicData;

        const { data: groupsData, error: groupsError } = await (supabase.from("groups" as any) as any)
          .select("id, code, line_id")
          .in("id", groupIds);
        if (groupsError) throw groupsError;

        return basicData.map((gl: any) => ({
          ...gl,
          groups: groupsData?.find((g: any) => g.id === gl.group_id) ?? null,
        }));
      } catch (err) {
        console.warn("group_leaders access denied:", err);
        return [];
      }
    },
    enabled: !!userId,
  });
}

// ─── Line-scoped data ─────────────────────────────────────────────────────────

export function useLineProducts(lineId?: string) {
  return useQuery({
    queryKey: ["line_products", lineId],
    queryFn: async () => {
      if (!lineId) return [];
      try {
        const { data, error } = await (supabase.from("product_lines" as any) as any)
          .select("product_id, products(id, code, name, model)")
          .eq("line_id", lineId);
        if (error) throw error;
        return (data ?? []).map((lp: any) => ({
          id: lp.product_id,
          ...(lp.products as any),
        }));
      } catch (err) {
        console.warn("product_lines access denied:", err);
        return [];
      }
    },
    enabled: !!lineId,
  });
}

export function useLineOperators(lineId?: string) {
  return useQuery({
    queryKey: ["line_operators", lineId],
    queryFn: async () => {
      if (!lineId) return [];
      try {
        const { data, error } = await (supabase.from("operator_line_assignments" as any) as any)
          .select("operator_id, operators(id, full_name, initials, employee_code, avatar_color, position)")
          .eq("line_id", lineId);
        if (error) throw error;
        return data ?? [];
      } catch (err) {
        console.warn("operator_line_assignments access denied:", err);
        return [];
      }
    },
    enabled: !!lineId,
  });
}

export function useLineGroups(lineId?: string) {
  return useQuery({
    queryKey: ["line_groups", lineId],
    queryFn: async () => {
      if (!lineId) return [];
      try {
        const { data, error } = await (supabase.from("groups" as any) as any)
          .select("id, code, line_id")
          .eq("line_id", lineId)
          .eq("active", true)
          .order("sort_order");
        if (error) throw error;
        return data ?? [];
      } catch (err) {
        console.warn("groups access denied:", err);
        return [];
      }
    },
    enabled: !!lineId,
  });
}

// ─── Group-scoped data ────────────────────────────────────────────────────────

export function useGroupPOS(groupId?: string) {
  return useQuery({
    queryKey: ["group_pos", groupId],
    queryFn: async () => {
      if (!groupId) return { groupId: null, groupCode: "", posData: [] };
      try {
        const { data: group, error: groupError } = await (supabase.from("groups" as any) as any)
          .select("id, code")
          .eq("id", groupId)
          .single();
        if (groupError) throw groupError;

        const { data: posData, error: posError } = await (supabase.from("group_process_assignments" as any) as any)
          .select(`
            process_id,
            processes(id, code, name)
          `)
          .eq("group_id", groupId);
        if (posError) throw posError;

        // Get the line_id from the group
        const { data: groupDetail } = await (supabase.from("groups" as any) as any)
          .select("line_id")
          .eq("id", groupId)
          .single();

        // Fetch operator assignments - first try process-level, then fall back to line-level
        let opAssignments: any[] = [];

        // Try process-level assignments first
        const { data: processOpAssignments, error: procOpError } = await (supabase.from("operator_process_assignments" as any) as any)
          .select(`
            operator_id,
            process_id,
            operators(id, full_name, initials, employee_code, avatar_color, position)
          `)
          .in("process_id", (posData ?? []).map((p: any) => p.process_id));

        if (!procOpError && processOpAssignments) {
          opAssignments = processOpAssignments;
        } else {
          console.warn("operator_process_assignments access denied, trying line-level:", procOpError);

          // Fall back to line-level operators if process-level fails or returns empty
          if (groupDetail?.line_id) {
            const { data: lineOpAssignments, error: lineOpError } = await (supabase.from("operator_line_assignments" as any) as any)
              .select(`
                operator_id,
                operators(id, full_name, initials, employee_code, avatar_color, position)
              `)
              .eq("line_id", groupDetail.line_id);

            if (!lineOpError && lineOpAssignments) {
              // Map line-level operators to all processes in the group
              opAssignments = (posData ?? []).flatMap((pos: any) =>
                (lineOpAssignments ?? []).map((op: any) => ({
                  ...op,
                  process_id: pos.process_id,
                }))
              );
            }
          }
        }

        // Transform data to match expected structure with default_assignments
        const transformedPosData = (posData ?? []).map((pos: any) => ({
          ...pos,
          default_assignments: opAssignments.filter((op: any) => op.process_id === pos.process_id),
        }));

        return { groupId, groupCode: (group as any).code, posData: transformedPosData };
      } catch (err) {
        console.warn("group_process_assignments access denied:", err);
        return { groupId, groupCode: "", posData: [] };
      }
    },
    enabled: !!groupId,
  });
}

